// Parse input from AI Agent tool call
const raw = $input.first().json;
let task = '';
try {
  const p = JSON.parse(raw.query || '{}');
  task = p.task || p.description || p.prompt || raw.query || '';
} catch(e) {
  task = raw.task || raw.query || JSON.stringify(raw);
}

const prompt = `You are an n8n workflow expert. Your task: create a complete, working n8n workflow.

TASK: ${task}

STEPS:
1. Read /workspace/n8n-reference/CHEATSHEET.md for API access, node types and workflow structure
2. Check example workflows in /workspace/n8n-reference/example-*.json
3. Create the workflow JSON file
4. Create any required credentials via curl (see Cheatsheet)
5. Create the workflow via curl POST to the n8n API
6. Activate the workflow via curl POST
7. Reply with: workflow name, ID, and what it does

WICHTIG:
- Use curl for all API calls (NOT MCP)
- n8n expressions MÜSSEN mit = prefix starten: "={{ $json.field }}"
- All info is in CHEATSHEET.md
- Build COMPLETE, FUNCTIONAL workflows - no placeholders!`;

return [{json: {prompt, task}}];

// Extract Claude Code's response - try all possible fields
const result = $input.first().json;

// The node outputs: success, sessionId, output, rawOutput, exitCode, duration, cost, error
// 'output' should have the text result, 'rawOutput' has the full JSON
const output = result.output 
  || result.result 
  || result.text 
  || (result.rawOutput && result.rawOutput.result)
  || JSON.stringify(result);

return [{json: {
  response: output || 'Claude Code completed but returned no text output. Check n8n execution log for details.',
  cost: result.cost || (result.rawOutput && result.rawOutput.total_cost_usd) || null,
  session_id: result.sessionId || (result.rawOutput && result.rawOutput.session_id) || null,
  success: result.success,
  duration_s: result.duration ? Math.round(result.duration / 1000) : null,
  // Debug: include raw keys to diagnose empty outputs
  _debug_keys: Object.keys(result).join(','),
  _debug_output_length: (output || '').length
}}];
